const resp = items[0].json;
const headers = resp.headers || {};
const body = resp.body || {};
const data = body.products || [];
const linkHeader = headers.link || headers['Link'] || '';
const nextMatch = linkHeader.match(/<([^>]+)>; rel="next"/);
const nextUrl = nextMatch ? nextMatch[1] : null;
return [{ json: { allData: data, nextUrl: nextUrl, pageCount: 1 } }];

const prev = $node["Has More Pages?"].json;
const curr = items[0].json;
const body = curr.body || {};
const newData = body.products || [];
const allData = prev.allData.concat(newData);
const headers = curr.headers || {};
const linkHeader = headers.link || headers['Link'] || '';
const nextMatch = linkHeader.match(/<([^>]+)>; rel="next"/);
const nextUrl = nextMatch ? nextMatch[1] : null;
if (prev.pageCount >= 100) return [{ json: { allData: allData, nextUrl: null, pageCount: prev.pageCount + 1 } }];
return [{ json: { allData: allData, nextUrl: nextUrl, pageCount: prev.pageCount + 1 } }];

const all = items[0].json.allData || [];
const ids = [];
for (var i = 0; i < all.length; i++) {
  var variants = all[i].variants || [];
  for (var j = 0; j < variants.length; j++) {
    var iid = variants[j].inventory_item_id;
    if (iid) ids.push(iid.toString());
  }
}
const batches = [];
for (var i = 0; i < ids.length; i += 250) {
  batches.push(ids.slice(i, i + 250).join(','));
}
return [{ json: { products: all, batches: batches, batchIdx: 0, costMap: {} } }];

const state = $node["Has More Batches?"].json;
const resp = items[0].json;
const body = resp.body || resp;
const invItems = body.inventory_items || [];
const costMap = Object.assign({}, state.costMap);
for (var i = 0; i < invItems.length; i++) {
  var item = invItems[i];
  if (item && item.id !== undefined) {
    costMap[item.id.toString()] = item.cost !== undefined && item.cost !== null ? parseFloat(item.cost) : null;
  }
}
return [{ json: { products: state.products, batches: state.batches, batchIdx: state.batchIdx + 1, costMap: costMap } }];

const today = new Date().toISOString().split('T')[0];
const state = items[0].json;
const all = state.products || state.allData || [];
const costMap = state.costMap || {};
const results = [];
for (var i = 0; i < all.length; i++) {
  var p = all[i];
  var variants = p.variants || [];
  var fv = variants[0] || {};
  var qty = variants.reduce(function(s, v) { return s + (parseInt(v.inventory_quantity) || 0); }, 0);
  var imgs = p.images || [];
  var inventoryItemId = (fv.inventory_item_id || '').toString();
  var cost = costMap.hasOwnProperty(inventoryItemId) ? costMap[inventoryItemId] : null;
  results.push({ json: {
    date: today,
    product_id: (p.id || '').toString(),
    product_title: p.title || '',
    product_description: p.body_html || '',
    product_handle: p.handle || '',
    product_image_src: imgs.length > 0 ? imgs[0].src : '',
    product_inventory_quantity: qty,
    product_price: parseFloat(fv.price) || 0,
    product_status: (p.status || '').toUpperCase(),
    product_tags: p.tags || '',
    product_type: p.product_type || '',
    product_created_at_datetime: p.created_at || null,
    product_updated_at_datetime: p.updated_at || null,
    product_variant_inventory_item_cost: cost,
    product_vendor: p.vendor || ''
  }});
}
if (results.length === 0) return [{ json: { message: 'No products found' } }];
return results;

